#!/usr/bin/env python3
"""
Dependency Lockfile Management Guide and Helper Script

This file serves as both documentation and a lightweight helper for managing
Python dependency specifications and lock files for consistent development and
production environments.

Supported workflows:
- requirements.txt with pinned versions
- requirements.txt with hashes
- Poetry pyproject.toml + poetry.lock

Recommended best practices:
- Pin exact versions for production deployments.
- Use lock files or hash-locked requirements for reproducibility.
- Regenerate lock files only when intentionally updating dependencies.
- Commit lock files to version control.
- Use the same Python version across dev, CI, and production where possible.

-------------------------------------------------------------------------------
1) REQUIREMENTS.TXT WORKFLOW
-------------------------------------------------------------------------------

A) Generate a pinned requirements file from your current environment:
   pip freeze > requirements.txt

This captures installed versions, but it is not ideal as a source of truth for
long-term maintenance because it reflects a local environment.

B) Better: maintain a top-level input file and compile a locked output file.

Example:
   requirements.in
     requests
     fastapi

Compile pinned dependencies:
   pip install pip-tools
   pip-compile requirements.in --output-file requirements.txt

Install exactly from the lock file:
   pip install -r requirements.txt

Update dependencies:
   pip-compile --upgrade requirements.in --output-file requirements.txt

If you want to update only one package:
   pip-compile --upgrade-package requests requirements.in --output-file requirements.txt

C) Generate requirements with hashes for stronger integrity:
   pip-compile --generate-hashes requirements.in --output-file requirements.txt

Then install with:
   pip install --require-hashes -r requirements.txt

This ensures every artifact has a matching hash.

-------------------------------------------------------------------------------
2) POETRY WORKFLOW
-------------------------------------------------------------------------------

A) Add dependencies:
   poetry add requests fastapi

B) Install exactly from the lock file:
   poetry install

C) Update all dependencies:
   poetry update

D) Update a single dependency:
   poetry update requests

E) Regenerate lock file after editing pyproject.toml:
   poetry lock

Poetry keeps dependency constraints in pyproject.toml and exact resolved versions
in poetry.lock. Commit both files.

-------------------------------------------------------------------------------
3) RECOMMENDED TEAM PRACTICES
-------------------------------------------------------------------------------

- Commit lock files to git:
  - requirements.txt if it is the lock file
  - poetry.lock for Poetry projects
- Do not manually edit lock files unless you know exactly what you are doing.
- Use automated dependency update tools:
  - pip-tools for requirements-based projects
  - Poetry for Poetry-based projects
  - Dependabot or Renovate for PR-based dependency updates
- Separate direct dependencies from transitive dependencies:
  - direct dependencies live in requirements.in or pyproject.toml
  - resolved versions live in requirements.txt or poetry.lock
- Rebuild lock files in CI when validating dependency changes.
- Prefer exact version pinning for production deployments.
- If using hashes, always install with --require-hashes.
- Keep Python version constraints explicit.

-------------------------------------------------------------------------------
4) EXAMPLE COMMANDS
-------------------------------------------------------------------------------

Requirements + pip-tools:
   pip install pip-tools
   pip-compile requirements.in --output-file requirements.txt
   pip-compile --upgrade requirements.in --output-file requirements.txt
   pip install -r requirements.txt

Poetry:
   poetry lock
   poetry install
   poetry update
   poetry add package-name
   poetry remove package-name

-------------------------------------------------------------------------------
5) HELPER SCRIPT
-------------------------------------------------------------------------------

This script can:
- show guidance
- validate that a requirements file is pinned
- detect whether a requirements file contains hashes
- print a minimal workflow summary

Usage:
   python dependency_lock_manager.py guide
   python dependency_lock_manager.py check-requirements requirements.txt
   python dependency_lock_manager.py check-requirements requirements.txt --require-hashes

"""

from __future__ import annotations

import argparse
import re
import sys
from pathlib import Path


REQ_LINE_RE = re.compile(
    r"""
    ^
    (?P<name>[A-Za-z0-9_.\-]+)
    (?P<extras>\[[A-Za-z0-9_,.\-]+\])?
    (?P<specifier>(==|===)[^;#\s]+)?
    (?P<markers>\s*;\s*[^#]+)?
    (?P<hashes>(\s+--hash=sha256:[A-Fa-f0-9]{64})+)?
    (\s*#.*)?
    $
    """,
    re.VERBOSE,
)

COMMENT_OR_EMPTY_RE = re.compile(r"^\s*(#.*)?$")


GUIDE_TEXT = """Dependency management best practices

Requirements-based workflow:
1. Define top-level dependencies in requirements.in
2. Compile a locked requirements.txt with pip-tools:
   pip-compile requirements.in --output-file requirements.txt
3. Install from the lock file:
   pip install -r requirements.txt
4. For hash-locked installs:
   pip-compile --generate-hashes requirements.in --output-file requirements.txt
   pip install --require-hashes -r requirements.txt
5. Update dependencies intentionally:
   pip-compile --upgrade requirements.in --output-file requirements.txt
   pip-compile --upgrade-package PACKAGE requirements.in --output-file requirements.txt

Poetry workflow:
1. Define dependencies in pyproject.toml
2. Lock exact versions:
   poetry lock
3. Install from lock:
   poetry install
4. Update all dependencies:
   poetry update
5. Update one dependency:
   poetry update PACKAGE

Team rules:
- Commit lock files to version control.
- Do not mix unpinned and locked installs in production.
- Use the same Python version in dev, CI, and prod.
- Review dependency updates before merging.
- Prefer automated update PRs.
"""


def is_pinned_requirement(line: str) -> bool:
    line = line.strip()
    if not line or line.startswith("#"):
        return True
    if line.startswith(("-", "git+", "http://", "https://", "file:")):
        return False
    if line.startswith(("-r ", "--requirement ", "-c ", "--constraint ")):
        return True
    if line.startswith(("--index-url", "--extra-index-url", "--trusted-host", "--find-links", "--no-index")):
        return True
    if "==" in line or "===" in line:
        return True
    return False


def has_hashes(line: str) -> bool:
    return "--hash=sha256:" in line


def check_requirements_file(path: Path, require_hashes: bool = False) -> int:
    if not path.exists():
        print(f"ERROR: file not found: {path}", file=sys.stderr)
        return 2

    text = path.read_text(encoding="utf-8", errors="replace").splitlines()
    bad_lines = []
    missing_hash_lines = []

    for idx, line in enumerate(text, start=1):
        if COMMENT_OR_EMPTY_RE.match(line):
            continue
        stripped = line.strip()

        if stripped.startswith(("-r ", "--requirement ", "-c ", "--constraint ")):
            continue
        if stripped.startswith(("--index-url", "--extra-index-url", "--trusted-host", "--find-links", "--no-index")):
            continue

        if not is_pinned_requirement(stripped):
            bad_lines.append((idx, line))

        if require_hashes and not has_hashes(stripped):
            if not stripped.startswith(("-", "git+", "http://", "https://", "file:")):
                missing_hash_lines.append((idx, line))

    if bad_lines:
        print("Unpinned requirements detected:")
        for idx, line in bad_lines:
            print(f"  {path}:{idx}: {line}")
    else:
        print("All requirements appear pinned.")

    if require_hashes:
        if missing_hash_lines:
            print("Missing hashes detected:")
            for idx, line in missing_hash_lines:
                print(f"  {path}:{idx}: {line}")
        else:
            print("All applicable requirements contain hashes.")

    return 1 if (bad_lines or (require_hashes and missing_hash_lines)) else 0


def main() -> int:
    parser = argparse.ArgumentParser(
        description="Dependency lockfile management helper"
    )
    sub = parser.add_subparsers(dest="command", required=True)

    sub.add_parser("guide", help="Print dependency management guidance")

    chk = sub.add_parser("check-requirements", help="Validate a requirements file")
    chk.add_argument("path", type=Path)
    chk.add_argument(
        "--require-hashes",
        action="store_true",
        help="Require --hash entries for all applicable requirements",
    )

    args = parser.parse_args()

    if args.command == "guide":
        print(GUIDE_TEXT)
        return 0

    if args.command == "check-requirements":
        return check_requirements_file(args.path, require_hashes=args.require_hashes)

    return 2


if __name__ == "__main__":
    raise SystemExit(main())